INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('retired-d0d1b9a2-moex-00370', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-110-78566e18', 'sub-retired-d0d1b9a2-01', NULL, 'single_choice', '乙公司採用曆年制之會計年度，並於X1年7月1日向丙銀行借款$500,000，到期日為X5年 6月30日。此外，乙公司在X4年12月10日向丙銀行提出協議，$400,000積欠款項之還款 日期延後至X8年6月30日，達成此項協議為X5年1月10日，乙公司X4年度財務報表於 X5年2月15日發布。請問：乙公司上述負債$500,000在X4年12月31日資產負債表之分 類為何？', '["流動負債$500,000", "流動負債$100,000，非流動負債$400,000", "非流動負債$500,000", "乙公司自行決定流動與非流動負債之金額分類 70130"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:13+00:00", "source_pdf_sha1": "d5a7716368cf", "answer_pdf_sha1": "7fa06cc4de90", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "136", "s": "1901", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00371', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-110-78566e18', 'sub-retired-d0d1b9a2-01', NULL, 'single_choice', '丙公司數年前以$500,000購入機器設備，至X1年12月31日之累計折舊為$100,000，甲公司 意圖繼續使用該機器設備，剩餘耐用年限為10年，估計無殘值，以直線法提列折舊。然而， 因產品競爭之變化，丙公司於X1年12月31日評估，該機器設備具有減損跡象，此時，公 允價值減處分成本為$350,000，使用價值為$380,000。此外，X2年4月1日因市場策略調整， 丙公司決定將機器設備予以出售，符合待出售條件，當日機器設備之公允價值減處分成本為 $330,000，使用價值為$340,000。試問：X2年4月1日丙公司應記錄之「待出售機器設備」 帳面金額為何？', '["$330,000", "$340,000", "$370,500", "$390,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:13+00:00", "source_pdf_sha1": "d5a7716368cf", "answer_pdf_sha1": "7fa06cc4de90", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "136", "s": "1901", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00372', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-110-78566e18', 'sub-retired-d0d1b9a2-01', NULL, 'single_choice', '戊公司於X1年1月1日與客戶簽訂一項建造合約，合約固定價格為$200,000，此合約預計3年 完成。戊公司評估建造合約履約義務之完成程度能合理衡量。3年建造期間的成本資料如下： X1年 X2年 X3年 至今已累積成本 $48,000 $120,000 $180,000 估計總合約成本 160,000 240,000 180,000 請問：戊公司X2年度認列之工程利潤（損失）為何？', '["$(52,000)", "$(40,000)", "$(32,000)", "$(20,000)"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:13+00:00", "source_pdf_sha1": "d5a7716368cf", "answer_pdf_sha1": "7fa06cc4de90", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "136", "s": "1901", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00373', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-110-78566e18', 'sub-retired-d0d1b9a2-01', NULL, 'single_choice', '甲公司於X1年12月1日經由股東會決議，依照股東持股比率，分配財產股利予股東，並決 議於X2年1月31日發放股利。此外，此項財產股利，係以甲公司於數月前購入乙公司之債 券作為分配（成本$780,000），依據甲公司之經營模式，此項投資分類為透過損益按公允價值 衡量之債券投資。投資之公允價值資料如下： 公允價值 X1年12月1日 $800,000 X1年12月31日 880,000 X2年1月31日 950,000 請問：尚未實際支付財產股利之X2年1月31日的「應付財產股利」應有餘額為何？', '["$780,000", "$800,000", "$880,000", "$950,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:13+00:00", "source_pdf_sha1": "d5a7716368cf", "answer_pdf_sha1": "7fa06cc4de90", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "136", "s": "1901", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00374', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-110-78566e18', 'sub-retired-d0d1b9a2-01', NULL, 'single_choice', '甲公司於X1年1月1日向乙公司承租一項運輸設備，租期10年，每年底支付租金$500,000， 租期屆滿日時，甲公司得以$10,000購入該運輸設備，在購入該設備之後，估計仍可繼續使用 該設備2年，屆時之殘值為零，甲公司對於不動產、廠房及設備以直線法提列折舊。X1年1 月1日租約簽訂時，雙方公司合理確定甲公司將於租期屆滿時，行使租約的購買選擇權。此 項運輸設備在X1年1月1日公允價值為$1,800,000。甲公司於安排此項租賃時，支付原始直 接成本$5,000；再者，甲公司得知此項租賃之隱含利率為 10%，同時，甲公司之增額借款利 率為12%。試問：X1 年12月31日，甲公司在此項租賃合約之「使用權資產」帳面金額為 何？（註：複利現值因子：10期10%=0.385543；10期12%=0.321973；12期10%=0.318631； 12期12%=0.256675；普通年金現值因子：10期10%=6.144567；10期12%=5.650223；12期 10%=6.813692；12期12%=6.194374）', '["$2,545,498", "$2,597,220", "$2,768,525", "$2,824,377 70130"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:13+00:00", "source_pdf_sha1": "d5a7716368cf", "answer_pdf_sha1": "7fa06cc4de90", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "136", "s": "1901", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00375', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-110-78566e18', 'sub-retired-d0d1b9a2-01', NULL, 'single_choice', '甲公司在X1年1月1日之廠房帳面金額為$1,200,000（成本$2,000,000，累計折舊$800,000）， 剩餘耐用年限10年，估計殘值$100,000，以直線法提列折舊。此外，X1年9月1日以$95,000 購入機器設備一部，估計耐用年限5年，殘值$5,000，並以年數合計法提列機器設備之折舊， 然而，因記帳疏失，漏列機器設備於X1年度之折舊。此項記帳疏失，在X2年底之結帳前已 被發現並更正。試問：假設不考慮所得稅影響，甲公司X2年度之折舊費用為何？', '["$134,000", "$138,000", "$140,000", "$148,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:13+00:00", "source_pdf_sha1": "d5a7716368cf", "answer_pdf_sha1": "7fa06cc4de90", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "136", "s": "1901", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00376', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-110-78566e18', 'sub-retired-d0d1b9a2-01', NULL, 'single_choice', '甲公司 X1 年初應收帳款餘額為$2,000,000，X1 年底應收帳款餘額為$1,300,000，X1 年沖銷 應收帳款$250,000，並於X1年底認列預期信用減損損失$20,000。若甲公司X1年度之銷貨收 入淨額為$5,800,000（全為賒銷），則X1年度甲公司向客戶收取之現金為何？', '["$6,250,000", "$6,290,000", "$6,500,000", "$6,750,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:13+00:00", "source_pdf_sha1": "d5a7716368cf", "answer_pdf_sha1": "7fa06cc4de90", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "136", "s": "1901", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00377', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-110-78566e18', 'sub-retired-d0d1b9a2-01', NULL, 'single_choice', '甲公司於X1年底以$100,000購入土地，並於X3年初以$150,000售出。該土地X2年底之公 允價值為$150,000。依稅法規定，土地應以成本作為課稅基礎，所得稅稅率為 20%。甲公司 X2年度及X3年度之稅前淨利均為$200,000，假設無其他暫時性差異存在，所有可減除之暫 時性差異，在未來很有可能有課稅所得可供此差異使用。若該土地符合分類為投資性不動產， 且後續衡量採公允價值模式，則甲公司X3年度認列所得稅之分錄為：', '["借記：遞延所得稅負債$10,000", "借記：遞延所得稅負債$50,000", "貸記：應付所得稅$30,000", "貸記：應付所得稅$40,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:13+00:00", "source_pdf_sha1": "d5a7716368cf", "answer_pdf_sha1": "7fa06cc4de90", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "136", "s": "1901", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00378', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-110-78566e18', 'sub-retired-d0d1b9a2-01', NULL, 'single_choice', '乙公司從事家電用品之產銷業務，其銷售之電視均附有2年之售後服務保證，顧客購買電視 後，如在2年內因製造小瑕疵而發生故障，均由乙公司免費更換零件及維修；因製造大瑕疵 而發生故障，則由乙公司更換電視。根據經驗，約有97%之電視不會發生瑕疵，2.5%之電視 會發生小瑕疵，0.5%之電視則會發生大瑕疵。每台電視發生小瑕疵與大瑕疵時之平均修理費 用分別為$1,000及$4,000。乙公司X1年度共銷售1,000台電視，每台售價為$8,000，X1年度 實際發生免費維修支出為$20,000。則 X1 年底乙公司帳列產品服務保證負債準備之餘額為 何？', '["$85,000", "$65,000", "$45,000", "$25,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:13+00:00", "source_pdf_sha1": "d5a7716368cf", "answer_pdf_sha1": "7fa06cc4de90", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "136", "s": "1901", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00379', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-110-78566e18', 'sub-retired-d0d1b9a2-01', NULL, 'single_choice', '甲公司之流動負債為$250,000，流動比率為3.0，速動比率為2.2，存貨週轉率為4.0，期初存 貨為$180,000，預付費用為$10,000。則甲公司銷貨成本之金額為何？', '["$540,000", "$720,000", "$740,000", "$760,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:13+00:00", "source_pdf_sha1": "d5a7716368cf", "answer_pdf_sha1": "7fa06cc4de90", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "136", "s": "1901", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL)
